import{_ as n,g as a,f as t,z as i}from"./chunks/framework.5qxeQQbV.js";const k=JSON.parse('{"title":"Kinh Pháp Môn Căn Bản","description":"Phân tích cách phàm phu, bậc hữu học, A-la-hán và Như Lai nhận thức về các pháp.","frontmatter":{"code":"MN 1","title":"Kinh Pháp Môn Căn Bản","pali":"Mūlapariyāya Sutta","group":"Căn bản pháp môn","translation":"thich-minh-chau","book":"trung-bo","description":"Phân tích cách phàm phu, bậc hữu học, A-la-hán và Như Lai nhận thức về các pháp."},"headers":[],"relativePath":"kinh/trung-bo/thich-minh-chau/mn-1-kinh-phap-mon-can-ban.md","filePath":"kinh/trung-bo/thich-minh-chau/mn-1-kinh-phap-mon-can-ban.md","lastUpdated":1782888167000}'),c={name:"kinh/trung-bo/thich-minh-chau/mn-1-kinh-phap-mon-can-ban.md"};function g(o,h,p,u,l,e){return a(),t("div",null,[...h[0]||(h[0]=[i('<p><em>Như vầy tôi nghe.</em></p><p>Một thời Thế Tôn trú tại (tụ lạc) Ukkattha, trong rừng Subhaga (rừng Hạnh phúc), dưới gốc cây Sa-la vương. Tại chỗ ấy, Thế Tôn gọi các Tỳ-kheo: &quot;Này các Tỳ-kheo!&quot;. – &quot;Bạch Thế Tôn&quot;, những Tỳ-kheo ấy vâng đáp Thế Tôn. Thế Tôn nói: &quot;Này các Tỳ-kheo. Ta sẽ giảng cho các ngươi &#39;Pháp môn căn bản tất cả pháp&#39;. Hãy nghe và khéo tác ý, Ta sẽ nói&quot;. – &quot;Thưa vâng, bạch Thế Tôn&quot;, những Tỳ-kheo ấy vâng đáp Thế Tôn. Thế Tôn nói như sau:</p><h2 id="pham-phu" tabindex="-1">(Phàm phu) <a class="header-anchor" href="#pham-phu" aria-label="Permalink to “(Phàm phu)”">​</a></h2><p>– Này các Tỳ-kheo, ở đây, có kẻ phàm phu ít nghe, không được thấy các bậc Thánh, không thuần thục pháp các bậc Thánh, không tu tập pháp các bậc Thánh, không được thấy các bậc Chơn nhân, không thuần thục pháp các bậc Chơn nhân, không tu tập pháp các bậc Chơn nhân, tưởng tri địa đại là địa đại. Vì tưởng tri địa đại là địa đại, người ấy nghĩ đến địa đại, nghĩ đến (tự ngã) đối chiếu với địa đại, nghĩ đến (tự ngã) như là địa đại, người ấy nghĩ: &quot;Địa đại là của ta&quot; – dục hỷ địa đại. Vì sao vậy? Ta nói người ấy không liễu tri địa đại.</p><p>Người ấy tưởng tri thủy đại là thủy đại... hỏa đại là hỏa đại... phong đại là phong đại. Vì tưởng tri như vậy, người ấy nghĩ: &quot;...đại là của ta&quot; – dục hỷ các đại ấy. Vì sao vậy? Ta nói người ấy không liễu tri các đại ấy.</p><blockquote><p>Hệ thống chuyển đổi từ các đại sang các cõi trời, các tầng thiền và cuối cùng là Niết-bàn, cho thấy sự chấp thủ sâu sắc của hạng phàm phu.</p></blockquote><h2 id="vi-huu-hoc" tabindex="-1">(Vị hữu học) <a class="header-anchor" href="#vi-huu-hoc" aria-label="Permalink to “(Vị hữu học)”">​</a></h2><p>Này các Tỳ-kheo, có Tỳ-kheo, hữu học tâm chưa thành tựu, đang sống cần cầu vô thượng an ổn khỏi khổ ách. Vị ấy thắng tri địa đại là địa đại. Vì thắng tri địa đại là địa đại, vị ấy đã không nghĩ đến địa đại, đã không nghĩ (tự ngã) đối chiếu với địa đại, đã không nghĩ: &quot;Địa đại là của ta&quot; – không dục hỷ địa đại. Vì sao vậy? Ta nói vị ấy có thể liễu tri địa đại.</p><p>Vị ấy thắng tri Niết-bàn là Niết-bàn; vì thắng tri Niết-bàn là Niết-bàn, vị ấy đã không nghĩ: &quot;Niết-bàn là của ta&quot; – không dục hỷ Niết-bàn. Vì sao vậy? Ta nói vị ấy có thể liễu tri Niết-bàn.</p><h2 id="bac-a-la-han" tabindex="-1">(Bậc A-la-hán) <a class="header-anchor" href="#bac-a-la-han" aria-label="Permalink to “(Bậc A-la-hán)”">​</a></h2><p>Lại nữa, này các Tỳ-kheo, có Tỳ-kheo là bậc A-la-hán, các lậu hoặc đã tận, tu hành thành mãn, các việc nên làm đã làm, đã đặt gánh nặng xuống, đã thành đạt tự lợi, đã tận trừ hữu kiết sử, chánh trí giải thoát. Vị ấy thắng tri địa đại là địa đại, không nghĩ: &quot;Địa đại là của ta&quot; – không dục hỷ địa đại. Vì sao vậy? Ta nói vị ấy đã liễu tri địa đại.</p><p>…</p><h2 id="đang-nhu-lai" tabindex="-1">(Đấng Như Lai) <a class="header-anchor" href="#đang-nhu-lai" aria-label="Permalink to “(Đấng Như Lai)”">​</a></h2><p>Này các Tỳ-kheo, Như Lai là bậc A-la-hán, Chánh Đẳng Giác, thắng tri địa đại là địa đại. Vì thắng tri địa đại là địa đại, Như Lai không nghĩ: &quot;Địa đại là của ta&quot; – không dục hỷ địa đại. Vì sao vậy? Ta nói vì Như Lai đã liễu tri địa đại từ lâu.</p><p>Thế Tôn thuyết giảng như vậy. Các Tỳ-kheo ấy hoan hỷ tín thọ lời dạy của Thế Tôn.</p>',15)])])}const T=n(c,[["render",g]]);export{k as __pageData,T as default};
